    for (const allowed of config.allowedReadPaths) {
      const resolvedAllowed = path.resolve(allowed);
      if (resolved === resolvedAllowed || isUnderDirectory(resolvedAllowed, resolved)) {
        isAllowed = true;
        break;
      }
